--// Kygra | TaleGuard(V0.1)
local _b = ""
local _g = 40
local _k = (_g * 15) - 442

local _d = (syn and syn.crypt and syn.crypt.b64_decode) or (crypt and crypt.b64decode) or function(data)
    local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    data = string.gsub(data, '[^'..b..'=]', '')
    return (data:gsub('.', function(x)
        if (x == '=') then return '' end
        local r,f='',(b:find(x)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r;
    end):gsub('%d%d%d%d%d%d%d%d', function(x)
        local r=0
        for i=1,8 do r=r+(x:sub(i,i)=='1' and 2^(8-i) or 0) end
        return string.char(r)
    end))
end

local _s = _d(_b)
local _r = {}

for i = 1, #_s do
    _r[i] = string.char(string.byte(_s, i) ~ _k)
end

local _run, _err = loadstring(table.concat(_r))
if _run then 
    _run() 
else 
    warn("[TaleGuard Error]: " .. tostring(_err)) 
end
